import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should calculate base premium for a single sword with first insurance surcharge and processing fee", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword" as const, material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      };

      const result = processScenario(scenario);

      // base premium 100G + 10% first insurance surcharge (10G) + 5G fee = 115G
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("should calculate correct base premium for each main item type", () => {
      const amuletScenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet" as const, material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      };
      const staffScenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff" as const, material: "oak", enchantment: 1, cursed: false },
            ],
          },
        ],
      };
      const potionScenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion" as const, material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      };

      // amulet: 60 + 10% (6) + 5 fee = 71G
      expect(processScenario(amuletScenario)).toEqual({ results: [{ premium: 71 }] });
      // staff: 80 + 10% (8) + 5 fee = 93G
      expect(processScenario(staffScenario)).toEqual({ results: [{ premium: 93 }] });
      // potion: 40 + 10% (4) + 5 fee = 49G
      expect(processScenario(potionScenario)).toEqual({ results: [{ premium: 49 }] });
    });
    it.todo("should calculate premium for a single component");
    it.todo("should sum premiums for multiple items in a quote");
    it.todo("should apply block pricing of 60G for 3 alike components");
    it.todo("should add 50% risk surcharge for cursed items");
    it.todo("should add 30% risk surcharge for highly enchanted items with enchantment level >= 5");
    it.todo("should apply 20% loyalty discount for customers with >= 2 years of business");
    it.todo("should apply 15% discount on contracts after the first with no first insurance surcharge");
    it.todo("should round amounts in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to items with enchantment >= 8 at 50%");
    it.todo("should fully reimburse damage to dragon material items");
  });

  describe("CLI", () => {
    it.todo("should read JSON scenario from stdin and write results to stdout");
  });
});

