const MAIN_ITEM_TYPES = ["sword", "amulet", "staff", "potion"];
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE = 0.10;
const PROCESSING_FEE = 5;

function roundInFavorOfMHPCO(amount: number): number {
  return Math.ceil(amount - 1e-9);
}

function calculateTotalBasePremium(items: any[]): number {
  let total = 0;
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (MAIN_ITEM_TYPES.includes(item.type)) {
      total += BASE_PREMIUMS[item.type];
    } else {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    }
  }

  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_PREMIUM + remainder * BASE_PREMIUMS[type];
  }

  return total;
}

export const processScenario = (scenario: any): unknown => {
  return {
    results: scenario.steps.map((step: any) => {
      const totalBasePremium = calculateTotalBasePremium(step.items);
      const premium = roundInFavorOfMHPCO(totalBasePremium * (1 + FIRST_INSURANCE_SURCHARGE)) + PROCESSING_FEE;
      return { premium };
    }),
  };
};

