        const isFirstQuote = quoteCount === 0;
        quoteCount++;
        let customerAdjustment: number;
        if (isFirstQuote) {
          customerAdjustment = isLoyalCustomer ? -LOYALTY_DISCOUNT : FIRST_INSURANCE_SURCHARGE;
        } else {
          customerAdjustment = -MULTI_CONTRACT_DISCOUNT;
        }
        const totalItemPremium = calculateTotalItemPremium(step.items);
        const premium = roundInFavorOfMHPCO(totalItemPremium * (1 + customerAdjustment)) + PROCESSING_FEE;
        return { premium };
      }
      return {};
    }),
  };
};

