it("should reimburse damage to items with enchantment >= 8 at 50%", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 5 },
    steps: [
      {
        op: "quote" as const,
        items: [
          { type: "amulet" as const, material: "silver", enchantment: 8, cursed: false },
        ],
